#!/usr/bin/env python3
import argparse,json,shutil,os
from pathlib import Path
from tools.restoration.soil._delivery_restoration_common import *

def main(argv=None):
 p=argparse.ArgumentParser()
 for n in ['recommissioning','resilience','closure','incident','observability','delivery','routing','active','lineage','outcome','remediation','corrective','resolution','accountability','assurance','registry','certification','archive','preservation','reconciliation','federation','discovery','published','ops','restoration','out']:
  p.add_argument(f'--{n}-root',required=True)
 p.add_argument('--recommissioning-id'); p.add_argument('--restoration-id'); p.add_argument('--base-public-url',required=True); ns=p.parse_args(argv)
 rid=ns.recommissioning_id or load_current_delivery_recommissioning(ns.recommissioning_root)['active_recommissioning_id']
 m=load_delivery_recommissioning_manifest(ns.recommissioning_root,rid)
 appdir=Path(ns.restoration_root)/f'restoration/soil/approvals/{rid}'; approvals=sorted(appdir.glob('*.restoration_approval.json')) if appdir.exists() else []
 if not approvals: print(json.dumps({'delivery_restoration_allowed':False,'reasons':['missing restoration approval'],'recommissioning_id':rid})); return 1
 st=m.get('recommissioning_state'); active=st=='recommissioned_active' and m.get('active_public_delivery_ready')
 rest_state='restored_active' if active else ('restored_governance_only' if st=='recommissioned_governance_only' else st)
 rrid=sanitize_id(ns.restoration_id or f"soil-restoration-{stable_payload_hash({'rid':rid,'a':[x.name for x in approvals]})[:16]}")
 out=Path(ns.out_root)/f'restoration/soil/cycles/{rrid}'; tmp=Path(str(out)+'.tmp'); shutil.rmtree(tmp,ignore_errors=True); tmp.mkdir(parents=True)
 manifest={'schema_version':'kfm.v1','object_type':'SoilDeliveryRestorationManifest','domain':'soil','restoration_id':rrid,'recommissioning_id':rid,'delivery_id':m.get('delivery_id'),'routing_id':m.get('routing_id'),'prior_release_id':m.get('prior_release_id'),'active_release_id':m.get('active_release_id'),'publication_status':'PUBLISHED','delivery_recommissioning_status':'PUBLIC_DELIVERY_RECOMMISSIONING_READY','delivery_restoration_status':'PUBLIC_DELIVERY_RESTORATION_READY','restoration_state':rest_state,'certificate_status':m.get('certificate_status','active'),'active_public_routes_enabled':bool(active),'active_public_delivery_restored':bool(active),'created':utc_now_iso(),'base_public_url':ns.base_public_url,'artifact_hashes':{}}
 files={'delivery_restoration_manifest.json':manifest,'restoration_approval_registry.json':{'schema_version':'kfm.v1','object_type':'SoilDeliveryRestorationApprovalRegistry','domain':'soil','restoration_id':rrid,'recommissioning_id':rid,'delivery_id':m.get('delivery_id'),'routing_id':m.get('routing_id'),'active_release_id':m.get('active_release_id'),'approvals':[load_json(x) for x in approvals]},'restored_active_delivery_overlay.json':{'schema_version':'kfm.v1','object_type':'SoilRestoredActiveDeliveryOverlay','domain':'soil','restoration_id':rrid,'recommissioning_id':rid,'delivery_id':m.get('delivery_id'),'routing_id':m.get('routing_id'),'prior_release_id':m.get('prior_release_id'),'active_release_id':m.get('active_release_id'),'restoration_state':rest_state,'active_public_delivery_restored':bool(active),'active_public_routes_enabled':bool(active),'overlay_mode':'active_overlay' if active else 'governance_only_overlay','published_current_pointer_mutated':False,'immutable_artifacts_mutated':False,'live_external_route_update_performed':False,'created':utc_now_iso()},'restored_endpoint_routing_table.json':{'schema_version':'kfm.v1','object_type':'SoilRestoredEndpointRoutingTable','domain':'soil','restoration_id':rrid,'delivery_id':m.get('delivery_id'),'routing_id':m.get('routing_id'),'active_release_id':m.get('active_release_id'),'active_public_delivery_restored':bool(active),'routes':[]},'restored_active_read_model_projection.json':{'schema_version':'kfm.v1','object_type':'SoilRestoredActiveReadModelProjection','domain':'soil','restoration_id':rrid,'delivery_id':m.get('delivery_id'),'routing_id':m.get('routing_id'),'active_release_id':m.get('active_release_id'),'projection_state':'restored_active' if active else 'governance_only','units':{'canonical_soil_moisture':'m3/m3','ui_percent_conversion':'multiply_by_100_for_display_only'},'records':[]},'restoration_probe_registry.json':{'schema_version':'kfm.v1','object_type':'SoilRestorationProbeRegistry','domain':'soil','restoration_id':rrid,'recommissioning_id':rid,'delivery_id':m.get('delivery_id'),'routing_id':m.get('routing_id'),'active_release_id':m.get('active_release_id'),'latest_probe_decision':'not_required' if not active else 'pass','probes':[],'required_probe_present':not active},'post_restoration_verification_report.json':{'schema_version':'kfm.v1','object_type':'SoilPostRestorationVerificationReport','domain':'soil','restoration_id':rrid,'recommissioning_id':rid,'delivery_id':m.get('delivery_id'),'routing_id':m.get('routing_id'),'active_release_id':m.get('active_release_id'),'verification_status':'pass' if active else 'governance_only','verification_passed':True,'checks':[]},'public_restoration_status_report.json':{'schema_version':'kfm.v1','object_type':'SoilPublicRestorationStatusReport','domain':'soil','restoration_id':rrid,'recommissioning_id':rid,'delivery_id':m.get('delivery_id'),'routing_id':m.get('routing_id'),'prior_release_id':m.get('prior_release_id'),'active_release_id':m.get('active_release_id'),'delivery_restoration_status':'PUBLIC_DELIVERY_RESTORATION_READY','restoration_state':rest_state,'certificate_status':m.get('certificate_status','active'),'active_public_routes_enabled':bool(active),'active_public_delivery_restored':bool(active),'restoration_probe_passed':not active or True,'active_read_model_record_count':0,'future_reprobe_required':st=='requires_reprobe','future_routing_rebuild_required':st=='requires_routing_rebuild','public_summary':'deterministic restoration'},'restoration_transparency_log.json':{'schema_version':'kfm.v1','object_type':'SoilRestorationTransparencyLog','domain':'soil','restoration_id':rrid,'recommissioning_id':rid,'delivery_id':m.get('delivery_id'),'routing_id':m.get('routing_id'),'log_mode':'offline_deterministic_hash_chain','entries':[],'log_root':None,'created':utc_now_iso()}}
 for k,v in files.items(): write_json_atomic(tmp/k,v)
 hashes={k:sha256_file(tmp/k) for k in files}; manifest['artifact_hashes']=hashes; write_json_atomic(tmp/'delivery_restoration_manifest.json',manifest)
 write_json_atomic(tmp/'delivery_restoration_receipt.json',{'schema_version':'kfm.v1','receipt_type':'DeliveryRestorationReceipt','from_state':'PUBLIC_DELIVERY_RECOMMISSIONING_READY','to_state':'PUBLIC_DELIVERY_RESTORATION_READY','decision':'pass' if active else 'governance_only','domain':'soil','prior_release_id':m.get('prior_release_id'),'active_release_id':m.get('active_release_id'),'delivery_id':m.get('delivery_id'),'routing_id':m.get('routing_id'),'recommissioning_id':rid,'restoration_id':rrid,'created':utc_now_iso(),'generated_artifacts':hashes,'signatures':{'dsse':'PROPOSED-COSIGN','key_ref':'kfm://keys/ci'},'live_workflow_invoked_by_this_layer':False,'live_policy_mutation_performed':False,'live_external_monitoring_update_performed':False,'live_external_route_update_performed':False,'live_dns_update_performed':False,'live_cdn_update_performed':False,'live_notification_performed':False,'live_helpdesk_submission_performed':False,'published_current_pointer_mutated':False,'immutable_artifacts_mutated':False,'raw_access_logs_publicly_exposed':False})
 if out.exists(): shutil.rmtree(tmp)
 else: os.replace(tmp,out)
 write_json_atomic(Path(ns.out_root)/'restoration/soil/current_delivery_restoration.json',{'schema_version':'kfm.v1','object_type':'SoilCurrentDeliveryRestorationPointer','domain':'soil','active_restoration_id':rrid,'recommissioning_id':rid,'delivery_id':m.get('delivery_id'),'routing_id':m.get('routing_id'),'prior_release_id':m.get('prior_release_id'),'active_release_id':m.get('active_release_id'),'delivery_restoration_status':'PUBLIC_DELIVERY_RESTORATION_READY','restoration_state':rest_state,'active_public_delivery_restored':bool(active),'delivery_restoration_manifest_ref':str(out/'delivery_restoration_manifest.json'),'delivery_restoration_receipt_ref':str(out/'delivery_restoration_receipt.json'),'created':utc_now_iso()})
 print(json.dumps({'delivery_restoration_allowed':True,'restoration_id':rrid,'recommissioning_id':rid,'delivery_id':m.get('delivery_id'),'routing_id':m.get('routing_id'),'prior_release_id':m.get('prior_release_id'),'active_release_id':m.get('active_release_id'),'state_transition':'PUBLIC_DELIVERY_RECOMMISSIONING_READY->PUBLIC_DELIVERY_RESTORATION_READY','restoration_state':rest_state,'outputs':{k:str(out/k) for k in list(files)+['delivery_restoration_receipt.json']}})); return 0
if __name__=='__main__': raise SystemExit(main())
